class Solution {
    bool dfs(vector<int>& a, vector<char>& used, int k, int target, int cur, int start){
        if(k==1) return true;
        if(cur==target) return dfs(a,used,k-1,target,0,0);
        for(int i=start;i<(int)a.size();i++){
            if(used[i]||cur+a[i]>target) continue;
            used[i]=1; if(dfs(a,used,k,target,cur+a[i],i+1)) return true; used[i]=0;
        }
        return false;
    }
public:
    bool canPartitionKSubsets(vector<int>& a, int k) {
        int s=accumulate(a.begin(),a.end(),0); if(s%k) return false;
        sort(a.rbegin(),a.rend()); vector<char> used(a.size());
        return dfs(a,used,k,s/k,0,0);
    }
};

