static int cmp698(const void* x,const void* y){ return *(int*)y-*(int*)x; }
static int dfs698(int* a,int n,char* used,int rem,int target,int cur,int start){
    if(rem==1) return 1;
    if(cur==target) return dfs698(a,n,used,rem-1,target,0,0);
